chart.config_raw:
const ctx = document.getElementById('paradigmChart').getContext('2d');
new Chart(ctx, {
  type: 'bar',
  data: {
    labels: [
      'Architectural\nFrameworks',
      'Ethics &\nGovernance',
      'Emerging\nTechnologies',
      'Financial\nSystems',
      'Healthcare',
      'Robotics &\nAutomation',
      'Evaluation &\nBenchmarking',
      'Foundational\nTheories',
      'Education',
      'Legal &\nCompliance'
    ],
    datasets: [{
      label: 'Neural',
      data: [13, 23, 0, 5, 0, 0, 5, 0, 2, 1],
      backgroundColor: '#f6ad55',
      borderRadius: 4,
      barPercentage: 0.75,
      categoryPercentage: 0.7
    },
    {
      label: 'Symbolic / Hybrid',
      data: [0, 0, 25, 0, 4, 5, 0, 6, 0, 0],
      backgroundColor: '#4dabf7',
      borderRadius: 4,
      barPercentage: 0.75,
      categoryPercentage: 0.7
    }]
  },
  options: {
    animation: false,
    responsive: true,
    maintainAspectRatio: true,
    plugins: {
      title: {
        display: true,
        text: 'Agentic AI Literature by Category and Paradigm',
        font: { size: 15, weight: '700', family: "system-ui, -apple-system, 'Segoe UI', sans-serif" },
        color: '#1a1a1a',
        padding: { bottom: 16 }
      },
      legend: {
        position: 'top',
        labels: {
          font: { size: 12, family: "system-ui, -apple-system, 'Segoe UI', sans-serif" },
          color: '#4a5568',
          usePointStyle: true,
          pointStyle: 'rectRounded',
          padding: 16
        }
      },
      tooltip: {
        callbacks: {
          label: function(context) {
            return context.dataset.label + ': ' + context.parsed.y + ' papers';
          }
        }
      }
    },
    scales: {
      x: {
        grid: { display: false },
        ticks: {
          font: { size: 10.5, family: "system-ui, -apple-system, 'Segoe UI', sans-serif" },
          color: '#718096',
          maxRotation: 45,
          minRotation: 0
        }
      },
      y: {
        beginAtZero: true,
        grid: { color: '#e2e8f0' },
        ticks: {
          font: { size: 11, family: "system-ui, -apple-system, 'Segoe UI', sans-serif" },
          color: '#718096',
          callback: function(value) { return value; }
        },
        title: {
          display: true,
          text: 'Number of papers',
          font: { size: 11.5, family: "system-ui, -apple-system, 'Segoe UI', sans-serif" },
          color: '#718096'
        }
      }
    }
  }
});
